const {Name}Context = createContext<{Name}ContextType | null>(null);

function use{Name}Context() {
  const ctx = useContext({Name}Context);
  if (!ctx) throw new Error('{Name} compound components must be used within <{Name}>');
  return ctx;
}

function {Name}({ children }: { children: React.ReactNode }) {
  const [state, setState] = useState(initialState);
  return (
    <{Name}Context.Provider value={{ state, setState }}>
      {children}
    </{Name}Context.Provider>
  );
}

{Name}.Item = function {Name}Item({ value }: { value: string }) {
  const { state, setState } = use{Name}Context();
  return <div onClick={() => setState(value)}>{value}</div>;
};

export { {Name} };

function with{Behavior}<P extends object>(
  WrappedComponent: React.ComponentType<P & {Injected}Props>
) {
  function Enhanced(props: P) {
    const injected = use{Behavior}();
    return <WrappedComponent {...props} {...injected} />;
  }
  Enhanced.displayName = `with{Behavior}(${WrappedComponent.displayName || WrappedComponent.name})`;
  return Enhanced;
}

interface {Name}Props<T> {
  children: (state: { data: T; loading: boolean; error: Error | null }) => React.ReactNode;
}

function {Name}<T>({ children }: {Name}Props<T>) {
  const { data, loading, error } = use{DataSource}<T>();
  return <>{children({ data, loading, error })}</>;
}

interface {Name}Props extends React.HTMLAttributes<HTMLDivElement> {
  variant?: 'primary' | 'secondary';
}

const {Name} = React.forwardRef<HTMLDivElement, {Name}Props>(
  ({ variant = 'primary', className, children, ...props }, ref) => {
    return (
      <div ref={ref} className={cn(styles[variant], className)} {...props}>
        {children}
      </div>
    );
  }
);

{Name}.displayName = '{Name}';
export { {Name} };

interface {Name}Props<T> {
  items: T[];
  renderItem: (item: T, index: number) => React.ReactNode;
  keyExtractor: (item: T) => string;
  emptyMessage?: string;
}

function {Name}<T>({ items, renderItem, keyExtractor, emptyMessage }: {Name}Props<T>) {
  if (items.length === 0) {
    return <p>{emptyMessage ?? 'No items'}</p>;
  }
  return (
    <ul>
      {items.map((item, i) => (
        <li key={keyExtractor(item)}>{renderItem(item, i)}</li>
      ))}
    </ul>
  );
}

interface {Name}Props {
  value?: string;
  defaultValue?: string;
  onChange?: (value: string) => void;
}

function {Name}({ value: controlledValue, defaultValue = '', onChange }: {Name}Props) {
  const [internalValue, setInternalValue] = useState(defaultValue);
  const isControlled = controlledValue !== undefined;
  const currentValue = isControlled ? controlledValue : internalValue;

  const handleChange = (newValue: string) => {
    if (!isControlled) setInternalValue(newValue);
    onChange?.(newValue);
  };

  return <input value={currentValue} onChange={(e) => handleChange(e.target.value)} />;
}

type {Name}Props<C extends React.ElementType = 'div'> = {
  as?: C;
  children: React.ReactNode;
} & Omit<React.ComponentPropsWithoutRef<C>, 'as' | 'children'>;

function {Name}<C extends React.ElementType = 'div'>({ as, children, ...props }: {Name}Props<C>) {
  const Component = as || 'div';
  return <Component {...props}>{children}</Component>;
}

